  1	import * as React from 'react';
  2	import { useTranslation } from 'react-i18next';
  3	import { EmptyState, EmptyStateVariant } from '@patternfly/react-core';
  4	import { sortable } from '@patternfly/react-table';
  5	import {
  6	  TableColumn,
  7	  VirtualizedTable,
  8	  useActiveColumns,
  9	} from '@openshift-console/dynamic-plugin-sdk';
 10	import PipelineRunsForRepositoriesRow from './PipelineRunsForRepositoriesRow';
 11	import {
 12	  SummaryProps,
 13	  sortByNumbers,
 14	  sortByProperty,
 15	  sortByTimestamp,
 16	  sortTimeStrings,
 17	  listPageTableColumnClasses as tableColumnClasses,
 18	} from '../utils';
 19	
 20	type PipelineRunsForRepositoriesListProps = {
 21	  summaryData: SummaryProps[];
 22	  summaryDataFiltered: SummaryProps[];
 23	  loaded: boolean;
 24	};
 25	
 26	const PipelineRunsForRepositoriesList: React.FC<
 27	  PipelineRunsForRepositoriesListProps
 28	> = ({ summaryData, summaryDataFiltered, loaded }) => {
 29	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 30	  const EmptyMsg = () => (
 31	    <EmptyState variant={EmptyStateVariant.lg}>
 32	      {t('No PipelineRuns found')}
 33	    </EmptyState>
 34	  );
 35	
 36	  const plrColumns = React.useMemo<TableColumn<SummaryProps>[]>(
 37	    () => [
 38	      {
 39	        id: 'repoName',
 40	        title: t('Repository'),
 41	        sort: (summary, direction: 'asc' | 'desc') =>
 42	          sortByProperty(summary, 'repoName', direction),
 43	        transforms: [sortable],
 44	        props: { className: tableColumnClasses[0] },
 45	      },
 46	      {
 47	        id: 'namespace',
 48	        title: t('Project'),
 49	        sort: (summary, direction: 'asc' | 'desc') =>
 50	          sortByProperty(summary, 'namespace', direction),
 51	        transforms: [sortable],
 52	        props: { className: tableColumnClasses[1] },
 53	      },
 54	      {
 55	        id: 'total',
 56	        title: t('Total Pipelineruns'),
 57	        sort: 'total',
 58	        transforms: [sortable],
 59	        props: { className: tableColumnClasses[2] },
 60	      },
 61	      {
 62	        id: 'totalDuration',
 63	        title: t('Total duration'),
 64	        sort: (summary, direction: 'asc' | 'desc') =>
 65	          sortTimeStrings(summary, 'total_duration', direction),
 66	        transforms: [sortable],
 67	        props: { className: tableColumnClasses[3] },
 68	      },
 69	      {
 70	        id: 'avgDuration',
 71	        title: t('Average duration'),
 72	        sort: (summary, direction: 'asc' | 'desc') =>
 73	          sortTimeStrings(summary, 'avg_duration', direction),
 74	        transforms: [sortable],
 75	        props: {
 76	          className: tableColumnClasses[4],
 77	          info: {
 78	            tooltip: t(
 79	              'An average of the time taken to run PipelineRuns. The trending shown is based on the time range selected. This metric does not show runs that are running or pending.',
 80	            ),
 81	            className: 'pipeline-overview__for-pipelines-list__tooltip',
 82	          },
 83	        },
 84	      },
 85	      {
 86	        id: 'successRate',
 87	        title: t('Success rate'),
 88	        sort: (summary, direction: 'asc' | 'desc') =>
 89	          sortByNumbers(summary, 'succeeded', direction),
 90	        transforms: [sortable],
 91	        props: {
 92	          className: tableColumnClasses[5],
 93	          info: {
 94	            tooltip: t(
 95	              'Success rate measure the % of successfully completed pipeline runs in relation to the total number of pipeline runs',
 96	            ),
 97	            className: 'pipeline-overview__for-pipelines-list__tooltip',
 98	          },
 99	        },
100	      },
101	      {
102	        id: 'lastRunTime',
103	        title: t('Last run time'),
104	        sort: (summary, direction: 'asc' | 'desc') =>
105	          sortByTimestamp(summary, 'last_runtime', direction),
106	        transforms: [sortable],
107	        props: { className: tableColumnClasses[6] },
108	      },
109	    ],
110	    [t],
111	  );
112	
113	  const [columns] = useActiveColumns({
114	    columns: plrColumns,
115	    showNamespaceOverride: false,
116	    columnManagementID: '',
117	  });
118	
119	  const isEmptyData =
120	    (!summaryDataFiltered || summaryDataFiltered.length === 0) &&
121	    (!summaryData || summaryData.length === 0);
122	
123	  if (isEmptyData) {
124	    return <EmptyMsg />;
125	  }
126	
127	  return (
128	    <VirtualizedTable
129	      columns={columns}
130	      Row={PipelineRunsForRepositoriesRow}
131	      data={summaryDataFiltered || summaryData}
132	      loaded={loaded}
133	      loadError={false}
134	      unfilteredData={summaryData}
135	      EmptyMsg={EmptyMsg}
136	    />
137	  );
138	};
139	
140	export default PipelineRunsForRepositoriesList;

